import { products } from "../data.js";
import type { Product } from "../types.js";

type ServiceResult<T> =
  | { ok: true; data: T }
  | { ok: false; status: number; error: string };

interface ListProductsFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

interface ProductListResult {
  products: Product[];
  summary: {
    count: number;
    totalInventoryValue: number;
    averagePrice: number;
  };
}

interface ProductDetailResult extends Product {
  isLowStock: boolean;
  inventoryValue: number;
}

export function listProducts(
  filters: ListProductsFilters
): ServiceResult<ProductListResult> {
  let filtered = [...products];

  if (filters.category !== undefined) {
    filtered = filtered.filter((p) => p.category === filters.category);
  }

  if (filters.minPrice !== undefined) {
    filtered = filtered.filter((p) => p.price >= filters.minPrice!);
  }

  if (filters.maxPrice !== undefined) {
    filtered = filtered.filter((p) => p.price <= filters.maxPrice!);
  }

  const totalValue = filtered.reduce((sum, p) => sum + p.price * p.stock, 0);
  const avgPrice =
    filtered.length > 0
      ? filtered.reduce((sum, p) => sum + p.price, 0) / filtered.length
      : 0;

  return {
    ok: true,
    data: {
      products: filtered,
      summary: {
        count: filtered.length,
        totalInventoryValue: Math.round(totalValue * 100) / 100,
        averagePrice: Math.round(avgPrice * 100) / 100,
      },
    },
  };
}

export function getProductById(id: number): ServiceResult<ProductDetailResult> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { ok: false, status: 404, error: "Product not found" };
  }

  const isLowStock = product.stock < 10;
  const inventoryValue = Math.round(product.price * product.stock * 100) / 100;

  return {
    ok: true,
    data: {
      ...product,
      isLowStock,
      inventoryValue,
    },
  };
}

export function adjustProductStock(
  id: number,
  adjustment: number
): ServiceResult<ProductDetailResult> {
  const product = products.find((p) => p.id === id);

  if (!product) {
    return { ok: false, status: 404, error: "Product not found" };
  }

  const newStock = product.stock + adjustment;
  if (newStock < 0) {
    return { ok: false, status: 400, error: "Insufficient stock" };
  }

  product.stock = newStock;

  return {
    ok: true,
    data: {
      ...product,
      isLowStock: product.stock < 10,
      inventoryValue: Math.round(product.price * product.stock * 100) / 100,
    },
  };
}

